86: fn tool_name_eq(candidate: &str, alias: &str) -> bool {
87:     let mut lhs = candidate.bytes().filter(|b| *b != b'_');
88:     let mut rhs = alias.bytes().filter(|b| *b != b'_');
89: 
90:     loop {
91:         match (lhs.next(), rhs.next()) {
92:             (Some(a), Some(b)) if a.eq_ignore_ascii_case(&b) => {}
93:             (None, None) => return true,
94:             _ => return false,
95:         }
96:     }
97: }
98: 
99: fn tool_name_matches(candidate: &str, aliases: &[&str]) -> bool {
100:     aliases.iter().any(|alias| tool_name_eq(candidate, alias))
101: }
