115: fn render_snapshot(main_transcript: &[ChatMessage]) -> String {
116:     let mut out = String::new();
117:     for msg in main_transcript {
118:         let role_label = match msg.role {
119:             Role::User => "User",
120:             Role::Assistant => "Assistant",
121:         };
