125:                     out.push_str(role_label);
126:                     out.push_str(": ");
127:                     out.push_str(s);
128:                     out.push('\n');
129:                 }
130:                 MessagePart::Reasoning(s) if !s.is_empty() => {
131:                     out.push_str(role_label);
