144:                     // advisor's own transcript handles that. Including them
145:                     // would double-count tokens AND let the advisor
146:                     // accidentally treat its own past suggestions as
147:                     // authoritative "main agent" decisions.
148:                 }
149:                 MessagePart::TaskStatus(_) | MessagePart::CompactBoundary { .. } => {}
150:                 _ => {}
